import { FilterSegmentVariables } from './filter-segment-variables';
import { Include } from './include';
export interface DetailedFilterSegment {
    /**
     * Defines the allowed operations of the current user.
     */
    allowedOperations?: Array<'READ' | 'WRITE' | 'DELETE' | 'SHARE'>;
    /**
     * Description of the filter-segment.
     */
    description?: string;
    /**
     * Optional unique identifier of the filter-segment. Used for Dynatrace Configuration as Code
     */
    externalId?: string;
    /**
     * List of includes of the filter-segment.
     */
    includes?: Include[];
    /**
     * Indicates if the filter-segment is publicly accessible within the tenant.
     */
    isPublic?: boolean;
    /**
     * Indicates if the segment is ready-made.
     */
    isReadyMade?: boolean;
    /**
     * Name of the filter-segment.
     */
    name: string;
    /**
     * Defines the owner of the filter-segment.
     */
    owner: string;
    /**
     * Unique identifier of the filter-segment.
     */
    uid: string;
    /**
     * Variables of the filter-segment.
     */
    variables?: FilterSegmentVariables;
    /**
     * Used for optimistic locking. Update requests define with this on which version the data updated is based on. This must match with the version stored, otherwise the update will fail due to concurrent modification.
     */
    version?: number;
}
